### Примеры

```v
// Привет всем разработчикам
areas := ['game', 'web', 'tools', 'science', 'systems',
          'embedded', 'drivers', 'GUI', 'mobile']
for a in areas { println('Hello, ${a} developers!') }

// Фильтрация логов
import os
text := os.read_file('app.log') or { eprintln(err); return }
for l in text.split_into_lines() {
    if l.starts_with('DEBUG:') { println(l) }
}

// HTTP + время
import net.http, time
t := time.unix(http.get('https://vlang.io/utc_now') or { return }.body.int())
println(t.format()) // 2019-08-16 17:48

// JSON
import json
struct User { name string; age int; mut: is_registered bool }
data := '[{"name":"Frodo","age":25},{"name":"Bobby","age":10}]'
mut users := json.decode([]User, data) or { return }
for mut u in users {
    if u.age < 16 { println('${u.name} too young'); continue }
    u.is_registered = true
}
println(json.encode(users))
```

